INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "仲間と夏を楽しむ、夏海の魔法士。自分を変えたいという固い決意で、障害物を無効化して走り続ける。", 1, 0.029, 1, 1.5, 1, 122601, 1, 0, 110, 101, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (111, "太陽よりも輝く、夏海の元気娘。　持ち前の身体能力で、どんなコースも柔軟に対応し、駆け抜ける。", 2, 0.014, 0, 2.5, 3, 122401, 2, 1, 105, 102, 120, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "波打ち際に煌めく、夏海の剣士。　日々の鍛錬で鍛えた脚で、長い距離も速度を落とさず走り切る。", 3, 0.017, 0, 2.5, 2, 122501, 3, 0, 110, 103, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "海の幸に目がない、渚のお姫様。　『王家の装備』の力を解放し、障害物をものともせず前へと進む。", 4, 0.016, 0, 1.5, 3, 107501, 4, 1, 110, 104, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "海でも主さまをお世話する、白浜の巫女。精霊の力で自身を加速させ、誰よりも速くゴールを目指す。", 5, 0.014, 1, 2.5, 1, 107601, 5, 0, 110, 105, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "水着姿を恥じらう、ツンデレ猫娘。お得意の魔法で、対戦相手の走りを妨害し、レースを有利に進める。", 6, 0.029, 0, 3.5, 2, 107801, 6, 0, 120, 106, 255, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "優雅に浜を駆ける、真夏のマホ姫。しゃなりしゃなりと、雅な身のこなしで障害物を跳び越えていく。", 7, 0.013, 1, 3.5, 1, 110601, 7, 0, 120, 107, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "浜の平和を守る、真夏の狼娘。　　獣人の強靭なスタミナで、レース　後半にスパートをかける。", 8, 0.014, 0, 2.5, 2, 110401, 8, 0, 110, 108, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (100, "浜に力強く舞う、真夏の南国娘。　レースの喧噪の中でも精神を乱さず後半に大きな捲りを見せる。", 9, 0.012, 0, 1.5, 3, 110501, 9, 1, 105, 109, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "浜の事件を嗅ぎ付けた、真夏の　　名探偵。高い推理力と魔法で、的確に対戦相手の走りを乱す。", 10, 0.014, 1, 2.5, 1, 115701, 10, 0, 105, 110, 200, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "再び鎧を脱いだ、灼熱の騎士団長。実戦で培った判断力で、瞬時にバリアを展開し、障害物を無力化する。", 11, 0.071, 0, 2.5, 2, 113601, 11, 0, 105, 111, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "水が苦手な、海辺の気まぐれ猫娘。浜に現れた美少女義賊は、対戦相手のスピードを奪いとる。", 12, 0.014, 0, 1.5, 3, 107901, 12, 1, 120, 112, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "バカンスも効率第一な、海の傭兵。レースでも最高効率を求め、どんな状況でも隙のない走りを見せる。", 13, 0.022, 1, 1.5, 2, 108001, 13, 0, 110, 113, 200, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (108, "真夏の太陽が良く似合う、海辺の　サレンママ。多才で器用、どんな　障害物もエレガントに越えていく。", 14, 0.031, 1, 2.5, 1, 110301, 14, 0, 110, 114, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "海に嵐を呼ぶ夏のドジっ娘メイド。日頃から災難に慣れており、多少　のトラブルには動じたりしない。", 15, 0.036, 0, 0.5, 1, 107701, 15, 1, 110, 115, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (95, "粋な夏を愉しむ、若夏の姉御。　　流麗な身体捌きで、始・継・終と、UBを重ねるごとに、加速する。", 16, 0.048, 0, 3.5, 2, 113101, 16, 0, 110, 116, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "夏のトキメキに触れた、オタク魔法少女。多彩な魔法を操り、少しずつ他の走者の速度を落とし続ける。", 17, 0.043, 0, 1.5, 3, 113301, 17, 1, 105, 117, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (95, "海獄に降臨せし、真夏の冥姫。　　レース後半に魔力を全解放し、　　蒼き疾風と成りて浜を駆け抜ける。", 18, 0.018, 0, 1.5, 2, 113201, 18, 1, 105, 118, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (108, "夏の夕を火花で彩る、渚の壊し屋。『壊し屋』の異名と過激な愛情は、対戦相手にプレッシャーを与える。", 19, 0.021, 1, 2.5, 2, 117001, 19, 0, 110, 119, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "青春に生きる者を導く、夏の先生。夢へと邁進する聖母の加護が、その身をあらゆる困難から守る。", 20, 0.036, 0, 2.5, 1, 113501, 20, 0, 110, 120, 255, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "笑顔の応援が眩しい、夏の超能力　ガール。超能力を駆使して、どんな障害物もひとっ飛びで乗り越える。", 21, 0.02, 0, 2.5, 3, 113401, 21, 0, 105, 121, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "海辺で大人の魅力を放つ、夏の　　セクシー先生。その魅力に囚われた対戦相手は、走りを乱してしまう。", 22, 0.018, 0, 2.5, 1, 110101, 22, 1, 110, 122, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (111, "水着も絶対外さない、夏のカリスマモデル。走りのバイブスは超テンアゲで、スピードはおにやば。", 23, 0.03, 1, 3.5, 3, 110001, 23, 0, 105, 123, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (103, "南の島も盛り上げる、真夏のアイドル。悪天候でも笑顔を絶やさず後半もリズムを上げて走り切る。", 24, 0.027, 0, 1.5, 1, 117201, 24, 1, 110, 124, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (108, "海原に美声を響かす、渚の歌姫。　守護の賛歌と精霊の加護により、　障害物から身を守る。", 25, 0.02, 1, 3.5, 2, 117301, 25, 0, 105, 125, 160, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "夏でも天邪鬼な、夕凪のテーラー。張り巡らされた魔法の糸で、他の走者の自由を奪う。", 26, 0.04, 0, 2.5, 3, 117401, 26, 0, 110, 126, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "向日葵が良く似合う、海辺の　　　お姉ちゃん。秘密結社の一員で、　抜群の身体能力が一番の武器。", 27, 0.009, 0, 3.5, 1, 117101, 27, 0, 110, 127, 350, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "渚でおっとり、夏色うさぎっこ。　うさぎさんパワー全開で、ぴょん　ぴょんとコースを跳ね回る。", 28, 0.022, 0, 3.5, 1, 122901, 28, 0, 120, 128, 255, 1);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (105, "無邪気さ弾ける、夏色いたずら娘。砂浜でも、いたずらの準備は万端！レースに大波乱が巻き起こる！？", 29, 0.028, 0, 2.5, 3, 122801, 29, 1, 110, 129, 130, 0);
INSERT INTO `v1_62ff5ee8856ff9906ca11539a1e4047f704170cfa1e794f8c4baec699a7bbbd1` VALUES (108, "海でも真面目な、夏色優等生。　　高めた魔力を解き放ち、一瞬の内に他の走者を置き去りにする。", 30, 0.023, 1, 3.5, 2, 122701, 30, 0, 105, 130, 130, 0);
